import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

class CalculatorTest {

    private Calculator calc;

    @BeforeEach
    void setUp() {
        calc = new Calculator();
    }

    @Test
    @DisplayName("Adding two positive numbers returns their sum")
    void addPositives() {
        assertEquals(5, calc.add(2, 3));
    }

    @Test
    void divideByZeroThrows() {
        ArithmeticException ex = assertThrows(
            ArithmeticException.class,
            () -> calc.divide(10, 0)
        );
        assertEquals("/ by zero", ex.getMessage());
    }

    @Test
    void multipleAssertions() {
        // assertAll: all assertions run even if one fails
        assertAll(
            () -> assertEquals(0,  calc.add(0, 0)),
            () -> assertEquals(-1, calc.add(1, -2)),
            () -> assertEquals(10, calc.add(5, 5))
        );
    }
}

import org.mockito.*;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.junit.jupiter.MockitoExtension;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class OrderServiceTest {

    @Mock
    private OrderRepository repo;

    @Mock
    private Notifier notifier;

    @InjectMocks
    private OrderService service; // Mockito injects @Mock fields

    @Test
    void placeOrderSavesAndNotifies() {
        Order order = new Order("item-1", 2);

        // Stub: when repo.save is called, return the order with id set
        when(repo.save(order)).thenReturn(order.withId(42L));

        service.place(order);

        // Verify interactions
        verify(repo).save(order);
        verify(notifier).sendConfirmation(argThat(o -> o.getId() == 42L));
    }

    @Test
    void captureArgument() {
        ArgumentCaptor<Order> captor = ArgumentCaptor.forClass(Order.class);
        service.place(new Order("item-1", 1));
        verify(repo).save(captor.capture());
        assertEquals("item-1", captor.getValue().getItemId());
    }
}

@Test
void transferReducesSenderBalance() {
    // Arrange
    Account sender    = new Account("alice", Money.of(100));
    Account recipient = new Account("bob",   Money.of(0));

    // Act
    sender.transfer(recipient, Money.of(30));

    // Assert
    assertEquals(Money.of(70), sender.getBalance());
    assertEquals(Money.of(30), recipient.getBalance());
}

