@WebMvcTest(OrderController.class)
class OrderControllerTest {

    @Autowired MockMvc mvc;
    @MockBean  OrderService service; // real service replaced with mock

    @Test
    void getOrder_returns200() throws Exception {
        when(service.findById(1L)).thenReturn(new Order(1L, "item"));

        mvc.perform(get("/orders/1"))
           .andExpect(status().isOk())
           .andExpect(jsonPath("$.id").value(1));
    }
}

// JPA layer test — real SQL, in-memory DB by default
@DataJpaTest
class OrderRepositoryTest {
    @Autowired OrderRepository repo;

    @Test
    void savedOrderIsRetrievable() {
        Order saved = repo.save(new Order(null, "item"));
        assertThat(repo.findById(saved.getId())).isPresent();
    }
}

// Real Postgres via Testcontainers
@SpringBootTest
@Testcontainers
class OrderServiceIT {
    @Container
    static PostgreSQLContainer<?> pg = new PostgreSQLContainer<>("postgres:16");

    @DynamicPropertySource
    static void props(DynamicPropertyRegistry r) {
        r.add("spring.datasource.url",      pg::getJdbcUrl);
        r.add("spring.datasource.username", pg::getUsername);
        r.add("spring.datasource.password", pg::getPassword);
    }
}
